create table dirkspzm32.isi_einheiten_umrechnungen_art (
    sid                       varchar2(2 char) not null enable,
    firma_nr                  number(2, 0) not null enable,
    artikel_id                number(*, 0) not null enable,
    mengeneinheit             varchar2(3 char) default 'STK' not null enable,
    created_date              date not null enable,
    created_login_id          number(*, 0),
    last_change_date          date,
    last_change_login_id      number(*, 0),
    besteht_aus_anzahl        number(*, 5) not null enable,
    besteht_aus_mengeneinheit varchar2(3 char) default 'STK' not null enable
);

alter table dirkspzm32.isi_einheiten_umrechnungen_art
    add constraint pk_isi_einheiten_um_art
        primary key ( artikel_id,
                      mengeneinheit,
                      besteht_aus_mengeneinheit,
                      firma_nr,
                      sid )
            using index enable;


